# scripts/audit_dashboard_ownership.py
import os, json, requests
from datetime import date, timedelta

GRAFANA_URL   = os.environ["GRAFANA_URL"]
GRAFANA_TOKEN = os.environ["GRAFANA_TOKEN"]
STALE_DAYS    = 180  # flag dashboards not reviewed in 6 months


def fetch_all_dashboards() -> list[dict]:
    resp = requests.get(
        f"{GRAFANA_URL}/api/search?type=dash-db&limit=500",
        headers={"Authorization": f"Bearer {GRAFANA_TOKEN}"},
        timeout=10,
    )
    resp.raise_for_status()
    return resp.json()


def parse_tags(tags: list[str]) -> dict:
    result = {}
    for tag in tags:
        if ":" in tag:
            k, v = tag.split(":", 1)
            result[k] = v
    return result


if __name__ == "__main__":
    issues = []
    cutoff = date.today() - timedelta(days=STALE_DAYS)
    for dash in fetch_all_dashboards():
        tags = parse_tags(dash.get("tags", []))
        uid = dash.get("uid", "?")
        title = dash.get("title", "?")
        if "owner" not in tags:
            issues.append(f"[NO-OWNER]  {uid}: {title}")
        if "reviewed" in tags:
            try:
                reviewed = date.fromisoformat(tags["reviewed"])
                if reviewed < cutoff:
                    issues.append(f"[STALE]     {uid}: {title} (last reviewed {reviewed})")
            except ValueError:
                issues.append(f"[BAD-DATE]  {uid}: {title} (invalid reviewed tag: {tags['reviewed']})")
        if "runbook" not in tags:
            issues.append(f"[NO-RUNBOOK] {uid}: {title}")
    if issues:
        print(f"Dashboard ownership issues ({len(issues)}):")
        for issue in issues:
            print(f"  {issue}")
    else:
        print("All dashboards have valid ownership metadata.")
